## Objective

Restore full binding CRUD (create, edit, delete) to AdapterCard. Currently AdapterCard only displays binding rows read-only. Users who configured an adapter and skipped the wizard bind step can never add a binding afterward. This task integrates the existing BindingDialog component (in `apps/client/src/layers/features/mesh/ui/BindingDialog.tsx`) into AdapterCard for full lifecycle management.

## Files to Modify

- `apps/client/src/layers/features/relay/ui/AdapterCard.tsx` (primary)
- `apps/client/src/layers/features/mesh/ui/BindingDialog.tsx` (extend with delete action)

## Implementation Steps

### 1. Add State and Hooks to AdapterCard

Add binding management state and mutation hooks at the top of the `AdapterCard` component:

```typescript
const [bindingDialogOpen, setBindingDialogOpen] = useState(false);
const [bindingDialogMode, setBindingDialogMode] = useState<'create' | 'edit'>('create');
const [editingBinding, setEditingBinding] = useState<AdapterBinding | null>(null);
const [showAllBindings, setShowAllBindings] = useState(false);
```

Import and use the mutation hooks:

```typescript
import { useCreateBinding, useUpdateBinding, useDeleteBinding } from '@/layers/entities/binding';
import { BindingDialog, type BindingFormValues } from '@/layers/features/mesh/ui/BindingDialog';
import type { AdapterBinding } from '@dorkos/shared/relay-schemas';
import { Link2, Plus } from 'lucide-react';

const createBinding = useCreateBinding();
const updateBinding = useUpdateBinding();
const deleteBinding = useDeleteBinding();
```

### 2. Add "Add Binding" to Kebab Menu

Insert a new `DropdownMenuItem` after the "Events" item in the kebab menu:

```typescript
<DropdownMenuItem onClick={() => {
  setBindingDialogMode('create');
  setEditingBinding(null);
  setBindingDialogOpen(true);
}}>
  <Link2 className="mr-2 size-3.5" />
  Add Binding
</DropdownMenuItem>
```

### 3. Make Binding Rows Clickable for Edit

Wrap each `AdapterBindingRow` in a button that opens BindingDialog in edit mode. The `adapterBindings` array (already computed via `useMemo`) contains the full binding objects needed for `editingBinding`.

Replace the current binding row rendering:

```typescript
{visibleBindings.map((row, idx) => {
  const binding = adapterBindings[idx];
  return (
    <button
      key={row.bindingId}
      type="button"
      className="group/row flex w-full cursor-pointer items-center gap-1.5 rounded px-1 py-0.5 text-left transition-colors hover:bg-muted/50"
      onClick={() => {
        setEditingBinding(binding);
        setBindingDialogMode('edit');
        setBindingDialogOpen(true);
      }}
    >
      <AdapterBindingRow
        agentName={row.agentName}
        sessionStrategy={row.sessionStrategy}
        chatId={row.chatId}
        channelType={row.channelType}
        canInitiate={row.canInitiate}
        canReply={row.canReply}
        canReceive={row.canReceive}
      />
    </button>
  );
})}
```

Note: `visibleBindings` uses the first `MAX_VISIBLE_BINDINGS` of `boundAgentRows`. The matching full binding is at the same index in `adapterBindings`. When `showAllBindings` is true, render all `boundAgentRows` instead of slicing.

### 4. Add "+" Button After Binding Rows

After the binding rows (and after overflow indicator), add:

```typescript
<Button
  variant="ghost"
  size="sm"
  className="mt-1 h-6 gap-1 px-2 text-xs text-muted-foreground hover:text-foreground"
  onClick={() => {
    setBindingDialogMode('create');
    setEditingBinding(null);
    setBindingDialogOpen(true);
  }}
>
  <Plus className="size-3" />
  Add binding
</Button>
```

### 5. Make "and X more" Clickable

Replace the static `<span>` with a button that toggles `showAllBindings`:

```typescript
{overflowCount > 0 && !showAllBindings && (
  <button
    type="button"
    className="mt-1 text-xs text-muted-foreground hover:text-foreground hover:underline"
    onClick={() => setShowAllBindings(true)}
  >
    and {overflowCount} more
  </button>
)}
{showAllBindings && boundAgentRows.length > MAX_VISIBLE_BINDINGS && (
  <button
    type="button"
    className="mt-1 text-xs text-muted-foreground hover:text-foreground hover:underline"
    onClick={() => setShowAllBindings(false)}
  >
    Show less
  </button>
)}
```

Update the visible bindings computation:

```typescript
const visibleBindings = showAllBindings ? boundAgentRows : boundAgentRows.slice(0, MAX_VISIBLE_BINDINGS);
```

### 6. Replace "No agent bound" Amber Text with CTA

Replace the current amber text block (lines 196-200 approximately):

```typescript
) : isConnected ? (
  <Button
    variant="ghost"
    size="sm"
    className="mt-1 h-6 gap-1 px-2 text-xs text-amber-600 hover:bg-amber-50 hover:text-amber-700 dark:text-amber-500 dark:hover:bg-amber-950"
    onClick={() => {
      setBindingDialogMode('create');
      setEditingBinding(null);
      setBindingDialogOpen(true);
    }}
  >
    <Plus className="size-3" />
    Add binding
  </Button>
) : null}
```

### 7. Render BindingDialog at Bottom of AdapterCard

Add a helper to look up agent names, then render the dialog after the existing `Sheet` component:

```typescript
const lookupAgentName = (agentId: string) =>
  agents.find((a) => a.id === agentId)?.name ?? agentId;

// After the Sheet component:
<BindingDialog
  open={bindingDialogOpen}
  onOpenChange={setBindingDialogOpen}
  mode={bindingDialogMode}
  initialValues={
    bindingDialogMode === 'edit' && editingBinding
      ? {
          adapterId: editingBinding.adapterId,
          agentId: editingBinding.agentId,
          sessionStrategy: editingBinding.sessionStrategy,
          label: editingBinding.label ?? '',
          chatId: editingBinding.chatId,
          channelType: editingBinding.channelType,
          canInitiate: editingBinding.canInitiate,
          canReply: editingBinding.canReply,
          canReceive: editingBinding.canReceive,
        }
      : { adapterId: instance.id }
  }
  adapterName={manifest.displayName}
  agentName={editingBinding ? lookupAgentName(editingBinding.agentId) : undefined}
  onConfirm={(values) => {
    if (bindingDialogMode === 'edit' && editingBinding) {
      updateBinding.mutate({ id: editingBinding.id, ...values });
    } else {
      createBinding.mutate(values);
    }
    setBindingDialogOpen(false);
  }}
  onDelete={editingBinding ? (bindingId) => {
    deleteBinding.mutate(bindingId);
    setBindingDialogOpen(false);
  } : undefined}
/>
```

### 8. Extend BindingDialog with Delete Action (in edit mode)

In `apps/client/src/layers/features/mesh/ui/BindingDialog.tsx`:

1. Add `onDelete` prop to `BindingDialogProps`:

```typescript
export interface BindingDialogProps {
  // ... existing props
  /** Called when user confirms deletion in edit mode. Only rendered when mode === 'edit'. */
  onDelete?: (bindingId: string) => void;
}
```

2. In the dialog footer, when `isEdit` and `onDelete` is provided, add a destructive "Delete" button on the left side:

```typescript
<ResponsiveDialogFooter className="border-t px-4 py-3">
  {isEdit && onDelete && (
    <AlertDialog>
      <AlertDialogTrigger asChild>
        <Button variant="ghost" size="sm" className="mr-auto text-destructive hover:text-destructive">
          <Trash2 className="mr-1.5 size-3.5" />
          Delete
        </Button>
      </AlertDialogTrigger>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Delete binding?</AlertDialogTitle>
          <AlertDialogDescription>
            This will disconnect {adapterName} from {agentName}. Messages will no longer be routed.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction onClick={() => onDelete(initialValues?.adapterId ?? '')}>Delete</AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  )}
  <Button variant="ghost" size="sm" onClick={handleCancel}>
    Cancel
  </Button>
  <Button size="sm" onClick={handleConfirm}>
    {isEdit ? 'Save Changes' : 'Create Binding'}
  </Button>
</ResponsiveDialogFooter>
```

Add necessary imports to BindingDialog.tsx:
```typescript
import { Trash2 } from 'lucide-react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/layers/shared/ui';
```

Note: The `onDelete` callback receives the binding ID. In AdapterCard, this is `editingBinding.id`. Pass it through the BindingDialog so the delete confirmation can use it. The binding ID should be stored as additional state or passed as a prop. One clean approach: accept `bindingId?: string` as a separate prop on BindingDialog, and pass `editingBinding?.id`.

## Acceptance Criteria

- AdapterCard kebab menu has "Add Binding" item that opens BindingDialog in create mode
- Clicking a binding row opens BindingDialog in edit mode with all fields pre-populated
- "+" button below bindings opens BindingDialog in create mode with adapterId pre-filled
- "and X more" text is clickable and expands to show all bindings; "Show less" collapses
- "No agent bound" amber text is replaced with "Add binding" button
- BindingDialog edit mode shows a destructive "Delete" button with confirmation dialog
- Create/update/delete mutations use existing entity hooks from `@/layers/entities/binding`

## Tests

Create `apps/client/src/layers/features/relay/ui/__tests__/AdapterCard.test.tsx`:

- Test that "Add binding" CTA renders when adapter is connected but has no bindings
- Test that clicking a binding row opens BindingDialog in edit mode (mock BindingDialog, verify props)
- Test that "+" button opens BindingDialog in create mode with correct adapterId
- Test that "and X more" click toggles to show all bindings
- Test that delete confirmation dialog prevents accidental deletion (verify mutation not called until confirmation)

## Objective

Fix the broken health bar click interaction. Currently, `handleFailedClick` in `RelayPanel.tsx` sets `activeTab='activity'` and calls `deadLetterRef.current?.scrollIntoView()`, but the `DeadLetterSection` only renders when `showFailures` is `true` (defaults to `false`). The ref target doesn't exist in the DOM when `scrollIntoView` fires, so nothing happens.

## Files to Modify

- `apps/client/src/layers/features/relay/ui/RelayPanel.tsx`
- `apps/client/src/layers/features/relay/ui/ActivityFeed.tsx`

## Implementation Steps

### 1. Add `autoShowFailures` Prop to ActivityFeed

In `apps/client/src/layers/features/relay/ui/ActivityFeed.tsx`, extend the props interface:

```typescript
interface ActivityFeedProps {
  enabled: boolean;
  /** Ref attached to the dead-letter section wrapper for scroll-to support. */
  deadLetterRef?: RefObject<HTMLDivElement | null>;
  /** Called when the user clicks "Set up an adapter" in the no-messages empty state. */
  onSwitchToAdapters?: () => void;
  /** When true, forces the dead letter section open (signal from health bar click). */
  autoShowFailures?: boolean;
}
```

Update the component signature to destructure the new prop:

```typescript
export function ActivityFeed({ enabled, deadLetterRef, onSwitchToAdapters, autoShowFailures }: ActivityFeedProps) {
```

Add an effect that responds to the signal:

```typescript
useEffect(() => {
  if (autoShowFailures) {
    setShowFailures(true);
  }
}, [autoShowFailures]);
```

### 2. Update RelayPanel to Pass Signal

In `apps/client/src/layers/features/relay/ui/RelayPanel.tsx`:

Add state and update the handler:

```typescript
const [autoShowFailures, setAutoShowFailures] = useState(false);

const handleFailedClick = useCallback(() => {
  setActiveTab('activity');
  setAutoShowFailures(true);
  // Reset after a tick so it can be triggered again
  setTimeout(() => setAutoShowFailures(false), 100);
  // Scroll deferred to allow section to mount
  setTimeout(() => {
    deadLetterRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }, 150);
}, []);
```

Add the `useCallback` import if not already present. Add the `useState` for `autoShowFailures`.

Pass the prop to ActivityFeed:

```typescript
<ActivityFeed
  enabled={relayEnabled}
  deadLetterRef={deadLetterRef}
  autoShowFailures={autoShowFailures}
  onSwitchToAdapters={() => setActiveTab('connections')}
/>
```

## Acceptance Criteria

- Clicking the degraded/critical health bar message switches to Activity tab
- Dead letter section automatically opens (visible in DOM)
- Page scrolls to the dead letter section
- Clicking multiple times re-triggers the behavior (reset mechanism works)
- When dead letter section is already open, clicking health bar still scrolls to it

## Tests

Create or extend `apps/client/src/layers/features/relay/ui/__tests__/ActivityFeed.test.tsx`:

- Test that `autoShowFailures={true}` sets `showFailures` to true (dead letter section renders)
- Test that `autoShowFailures` transitioning from false to true opens the section
- Test that the dead letter section ref is scrollable when `autoShowFailures` triggers

## Objective

Remove the dialog-on-dialog pattern where the BarChart3 icon button in `RelayHealthBar` opens a `DeliveryMetricsDashboard` dialog on top of the relay dialog. Instead, show key metrics as an inline summary row at the top of the Activity tab. The full `DeliveryMetricsDashboard` component and its dialog can be deleted.

## Files to Modify

- `apps/client/src/layers/features/relay/ui/ActivityFeed.tsx` (add MetricsSummary)
- `apps/client/src/layers/features/relay/ui/RelayHealthBar.tsx` (remove dialog trigger)
- `apps/client/src/layers/features/relay/ui/DeliveryMetrics.tsx` (delete file or repurpose)

## Implementation Steps

### 1. Create MetricsSummary Component

Create `apps/client/src/layers/features/relay/ui/MetricsSummary.tsx`:

```typescript
import { useDeliveryMetrics } from '@/layers/entities/relay';
import { cn } from '@/layers/shared/lib';

interface MetricsSummaryProps {
  /** When false, the query is skipped. */
  enabled: boolean;
}

/** Compact inline metrics row showing delivery counts and average latency. */
export function MetricsSummary({ enabled }: MetricsSummaryProps) {
  const { data: metrics } = useDeliveryMetrics();
  if (!enabled || !metrics) return null;

  const pills = [
    { label: 'Total', value: metrics.totalMessages, variant: 'default' as const },
    { label: 'Delivered', value: metrics.deliveredCount, variant: 'success' as const },
    {
      label: 'Failed',
      value: metrics.failedCount,
      variant: (metrics.failedCount > 0 ? 'danger' : 'default') as const,
    },
    {
      label: 'Dead Letter',
      value: metrics.deadLetteredCount,
      variant: (metrics.deadLetteredCount > 0 ? 'warning' : 'default') as const,
    },
  ];

  return (
    <div className="flex items-center gap-3 border-b px-4 py-2">
      {pills.map(({ label, value, variant }) => (
        <div key={label} className="flex items-center gap-1.5 text-xs">
          <span className="text-muted-foreground">{label}</span>
          <span
            className={cn(
              'font-medium tabular-nums',
              variant === 'success' && value > 0 && 'text-green-600 dark:text-green-500',
              variant === 'danger' && 'text-red-600 dark:text-red-500',
              variant === 'warning' && 'text-amber-600 dark:text-amber-500',
            )}
          >
            {value.toLocaleString()}
          </span>
        </div>
      ))}
      {metrics.avgDeliveryLatencyMs != null && (
        <div className="ml-auto flex items-center gap-1.5 text-xs">
          <span className="text-muted-foreground">Avg</span>
          <span className="font-medium tabular-nums">
            {metrics.avgDeliveryLatencyMs < 1000
              ? `${Math.round(metrics.avgDeliveryLatencyMs)}ms`
              : `${(metrics.avgDeliveryLatencyMs / 1000).toFixed(1)}s`}
          </span>
        </div>
      )}
    </div>
  );
}
```

